const canvas=document.createElement("canvas");canvas.id="star-canvas";document.body.insertBefore(canvas,document.body.firstChild);const ctx=canvas.getContext("2d");let stars=[];const numStars=300;function resize(){canvas.width=window.innerWidth;canvas.height=window.innerHeight}window.addEventListener("resize",resize);resize();class Star{constructor(){this.x=Math.random()*canvas.width;this.y=Math.random()*canvas.height;this.z=Math.random()*canvas.width;this.size=Math.random()*1.5;this.baseX=this.x;this.baseY=this.y}update(t,a){this.z-=.5;if(this.z<=0){this.z=canvas.width;this.x=Math.random()*canvas.width;this.y=Math.random()*canvas.height}let s=(t-canvas.width/2)*(canvas.width/this.z)*.05;let i=(a-canvas.height/2)*(canvas.width/this.z)*.05;let e=(this.x-canvas.width/2)*(canvas.width/this.z)+canvas.width/2-s;let n=(this.y-canvas.height/2)*(canvas.width/this.z)+canvas.height/2-i;let h=Math.max(1,this.size*(canvas.width/this.z));if(e>0&&e<canvas.width&&n>0&&n<canvas.height){let t=Math.floor(255-this.z/canvas.width*255);ctx.fillStyle=`rgba(${t}, ${t}, ${t+50}, ${1-this.z/canvas.width})`;ctx.fillRect(e,n,h,h)}}}for(let t=0;t<numStars;t++){stars.push(new Star)}let mouseX=canvas.width/2;let mouseY=canvas.height/2;document.addEventListener("mousemove",t=>{mouseX=t.clientX;mouseY=t.clientY});function animateStars(){ctx.fillStyle="rgba(3, 5, 10, 0.3)";ctx.fillRect(0,0,canvas.width,canvas.height);for(let t=0;t<numStars;t++){stars[t].update(mouseX,mouseY)}requestAnimationFrame(animateStars)}animateStars();